/** Map trip codes to gallery category for hero/thumbnail lookup */
export const TRIP_GALLERY_CATEGORY: Record<string, GalleryCategory> = {
  'NZ-6D5N': 'new-zealand',
  'NZ-6D5N-NOV': 'new-zealand',
  'TAS-3D2N': 'tasmania',
  'TAS-LH-4D3N': 'tasmania',
  'TAS-LH-3D2N-WIN': 'tasmania',
  'TAS-SU-4D3N': 'tasmania',
  'ULU-4D3N': 'outback',
  'BER-3D2N': 'nsw',
  'CAN-2D1N': 'nsw',
  'KIA-1DAY': 'nsw',
  'PSP-1DAY': 'nsw',
  'LAV-ANB-1D': 'nsw',
  'SYD-MW-WIN': 'sydney',
  'SYD-1DAY': 'sydney',
  'MEL-4D3N': 'melbourne',
}

export type GalleryFilter = 'all' | GalleryCategory

export function filterGalleryPhotos(filter: GalleryFilter): GalleryPhoto[] {
  if (filter === 'all') return GALLERY_PHOTOS
  return GALLERY_PHOTOS.filter((p) => p.category === filter)
}

/**
 * Returns undefined (→ TripPhotoHero's brand gradient placeholder) when a trip
 * has no matching category rather than guessing with an unrelated photo —
 * showing "no photo yet" is honest; showing the wrong destination's photo
 * (e.g. an NSW beach on the Uluru trip) actively misleads customers.
 */
export function getHeroPhotoForTrip(tripCode: string): GalleryPhoto | undefined {
  const category = TRIP_GALLERY_CATEGORY[tripCode.toUpperCase()]
  if (!category) return undefined
  return GALLERY_PHOTOS.find((p) => p.category === category)
}

/** Alternate gallery photo for hover/long-press preview (differs from card hero when possible) */
export function getPreviewPhotoForTrip(tripCode: string): GalleryPhoto | undefined {
  const hero = getHeroPhotoForTrip(tripCode)
  const category = TRIP_GALLERY_CATEGORY[tripCode.toUpperCase()]
  if (!category) return undefined
  const inCategory = GALLERY_PHOTOS.filter((p) => p.category === category)
  const alternate = inCategory.find((p) => p.id !== hero?.id)
  return alternate ?? hero ?? inCategory[0]
}

/**
 * All gallery photos for a trip's destination, keyed off the same category
 * mapping as the hero photo (rather than matching on id substrings — a
 * prefix like "tas" can accidentally match an unrelated photo whose id just
 * happens to start the same way, which is how a mislabeled Uluru photo once
 * ended up in the Tasmania trip's thumbnail strip).
 */
export function getGalleryPhotosForTrip(tripCode: string): GalleryPhoto[] {
  const category = TRIP_GALLERY_CATEGORY[tripCode.toUpperCase()]
  if (!category) return []
  return GALLERY_PHOTOS.filter((p) => p.category === category)
}

const _photoSrcCache = new Map<string, string>()

export function photoSrc(photo: GalleryPhoto): string {
  if (photo.url) return photo.url
  const cached = _photoSrcCache.get(photo.id)
  if (cached) return cached
  const base64 = photo.base64 ?? ''
  const src = base64.startsWith('data:') ? base64 : `data:image/jpeg;base64,${base64}`
  _photoSrcCache.set(photo.id, src)
  return src
}
